# Core math utilities module with base operations

class DataSource:
    """Base class for data sources providing raw values."""
    _values: list[int]

    def __init__(self, values: list[int]):
        self._values = values

    @virtual
    def get_values(self) -> list[int]:
        return self._values

    @virtual
    def count(self) -> int:
        return len(self._values)

def calculate_sum(values: list[int]) -> int:
    """Sum all values in a list."""
    result: int = 0
    for v in values:
        result += v
    return result

def calculate_mean(values: list[int]) -> float:
    """Calculate arithmetic mean of values."""
    if len(values) == 0:
        return 0.0
    total: int = calculate_sum(values)
    return float(total) / float(len(values))

