# Statistics module extending math_core

from math_core import DataSource, calculate_sum, calculate_mean

class Statistics(DataSource):
    """Extended data source with statistical operations."""

    def __init__(self, values: list[int]):
        super().__init__(values)

    @override
    def get_values(self) -> list[int]:
        return self._values

    def average(self) -> float:
        return calculate_mean(self._values)

    def min_value(self) -> int:
        if len(self._values) == 0:
            return 0
        min_val: int = self._values[0]
        for v in self._values:
            if v < min_val:
                min_val = v
        return min_val

    def max_value(self) -> int:
        if len(self._values) == 0:
            return 0
        max_val: int = self._values[0]
        for v in self._values:
            if v > max_val:
                max_val = v
        return max_val

def analyze_dataset(data: Statistics) -> dict[str, float]:
    """Create analysis report of a dataset."""
    result: dict[str, float] = {}
    result["sum"] = float(calculate_sum(data.get_values()))
    result["mean"] = data.average()
    result["min"] = float(data.min_value())
    result["max"] = float(data.max_value())
    result["count"] = float(data.count())
    return result
